mapper.select:
SELECT T.NAME, T.AP_NO, T.TARGET_ID, IFNULL(SL.STATUS , 'notscanned') AS SEARCH_STATUS FROM pi_targets T LEFT OUTER JOIN (SELECT TARGET_ID, AP_NO, STATUS, UPDATED FROM (SELECT TARGET_ID, AP_NO, STATUS, FROM_UNIXTIME(UPDATED, '%Y-%m-%d %H:%i:%s') AS UPDATED, RANK() OVER (PARTITION BY TARGET_ID, AP_NO ORDER BY UPDATED DESC) as rank FROM pi_scheduled_location ) AS SL WHERE RANK = 1) SL ON T.TARGET_ID = SL.TARGET_ID AND T.AP_NO = SL.AP_NO WHERE 1=1
AND T.TARGET_ID IN (
#{item}
)
AND T.TARGET_ID = ''
GROUP BY T.TARGET_ID, T.AP_NO

SELECT COUNT(T.TARGET_ID) AS TOTAL, COUNT(CASE WHEN T.SEARCH_STATUS = 'ERROR' THEN 1 END) AS ERROR, COUNT(CASE WHEN T.SEARCH_STATUS = 'SEARCHING' THEN 1 END) AS SEARCHED, COUNT(CASE WHEN T.SEARCH_STATUS = 'NONE' AND T.SEARCH_TIME = 0 THEN 1 END) AS WAIT, COUNT( CASE WHEN T.SEARCH_STATUS = 'NONE' AND T.SEARCH_TIME != 0 AND T.MATCHCNT = 0 OR T.SEARCH_STATUS = 'SEARCHED' AND T.MATCHCNT = 0 AND T.SEARCH_TIME != 0 THEN 1 END ) AS COMPLETE, COUNT(CASE WHEN INSTR(UPPER(T.SEARCH_STATUS), 'PAUSED') > 0 THEN 1 END) AS PAUSE, COUNT(CASE WHEN T.SEARCH_STATUS = 'NONE' AND T.MATCHCNT != 0 AND T.SEARCH_TIME != 0 OR T.SEARCH_STATUS = 'SEARCHED' AND T.MATCHCNT != 0 AND T.SEARCH_TIME != 0 THEN 1 END) AS SCANCOMP FROM ( SELECT PT.TARGET_ID, PT.SEARCH_STATUS, PT.MATCHCNT, PT.SEARCH_TIME FROM PI_TARGETS PT LEFT OUTER JOIN pi_agents A ON PT.NAME = A.AGENT_NAME AND PT.AP_NO = A.AP_NO LEFT OUTER JOIN pi_target_user TU ON PT.TARGET_ID = TU.TARGET_ID AND PT.AP_NO = TU.AP_NO WHERE 1=1
AND TU.USER_NO = #{user_no}
AND PT.TARGET_USE = 'Y' GROUP BY PT.TARGET_ID ) T

SELECT T.TARGET_ID, T.AP_NO, DATE_FORMAT(SG.REGDATE, '%Y년 %m월') AS REGDATE, T.NAME AS SERVER, (CASE WHEN T.SEARCH_STATUS = 'ERROR' THEN '오류' WHEN T.SEARCH_STATUS = 'SEARCHING' THEN '검색중' WHEN T.SEARCH_STATUS = 'NONE' AND T.SEARCH_TIME = 0 THEN '미검색' WHEN T.SEARCH_STATUS = 'NONE' AND T.SEARCH_TIME != 0 AND T.MATCHCNT = 0 OR T.SEARCH_STATUS = 'SEARCHED' AND T.MATCHCNT = 0 AND T.SEARCH_TIME != 0 THEN '결과없음' WHEN INSTR(UPPER(T.SEARCH_STATUS), 'PAUSED') > 0 THEN '일시정지' WHEN T.SEARCH_STATUS = 'NONE' AND T.MATCHCNT != 0 AND T.SEARCH_TIME != 0 OR T.SEARCH_STATUS = 'SEARCHED' AND T.MATCHCNT != 0 AND T.SEARCH_TIME != 0 THEN '검출' END) AS STATUS, IFNULL(TC.PATH_CNT, 0) AS FILE, IFNULL(TC.RRN, 0) AS TYPE1, IFNULL(TC.MOBILE_PHONE, 0) AS TYPE2, IFNULL(TC.ACCOUNT_NUM, 0) AS TYPE3, IFNULL(TC.CARD_NUM, 0) AS TYPE4, IFNULL(TC.FOREIGNER, 0) AS TYPE5, IFNULL(TC.DRIVER, 0) AS TYPE6, IFNULL(TC.EMAIL, 0) AS TYPE7, IFNULL(TC.PASSPORT, 0) AS TYPE8, IFNULL(TC.RRN + TC.MOBILE_PHONE + TC.ACCOUNT_NUM + TC.CARD_NUM + TC.FOREIGNER + TC.DRIVER + TC.EMAIL + TC.PASSPORT, 0) AS COUNT, (SELECT COUNT(DP.HASH_ID) FROM pi_data_processing DP WHERE T.TARGET_ID = DP.TARGET_ID AND T.AP_NO = DP.AP_NO) AS OWN, (SELECT ((CASE WHEN DP.PROCESSING_FLAG NOT IN (1,2) THEN COUNT(DP.HASH_ID) ELSE 0 END)) FROM pi_data_processing DP WHERE T.TARGET_ID = DP.TARGET_ID AND T.AP_NO = DP.AP_NO) AS FAL, (SELECT ((CASE WHEN DP.PROCESSING_FLAG = 3 THEN COUNT(DP.HASH_ID) ELSE 0 END)) FROM pi_data_processing DP WHERE T.TARGET_ID = DP.TARGET_ID AND T.AP_NO = DP.AP_NO) AS LEGAL, (SELECT ((CASE WHEN DP.PROCESSING_FLAG = 5 THEN COUNT(DP.HASH_ID) ELSE 0 END)) FROM pi_data_processing DP WHERE T.TARGET_ID = DP.TARGET_ID AND T.AP_NO = DP.AP_NO) AS SYS, (SELECT ((CASE WHEN DP.PROCESSING_FLAG = 1 THEN COUNT(DP.HASH_ID) ELSE 0 END)) FROM pi_data_processing DP WHERE T.TARGET_ID = DP.TARGET_ID AND T.AP_NO = DP.AP_NO) AS DEL FROM pi_ap_server AP, pi_targets T LEFT JOIN pi_total TC ON T.TARGET_ID = TC.TARGET_ID AND T.AP_NO = TC.AP_NO LEFT OUTER JOIN pi_schedule_targets ST ON T.TARGET_ID = ST.TARGET_ID LEFT OUTER JOIN pi_schedule_group SG ON SG.SCHEDULE_GROUP_ID = ST.SCHEDULE_GROUP_ID AND T.AP_NO = SG.TYPE WHERE 1=1 AND T.AP_NO = AP.AP_NO AND AP.IS_SERVER = 1
AND T.TARGET_ID IN (
#{item}
)
AND SG.REGDATE BETWEEN CONCAT(#{fromDate},' 00:00:00') AND CONCAT(#{toDate} ,' 23:59:59')
GROUP BY T.TARGET_ID, T.AP_NO ORDER BY FILE DESC

SELECT IFNULL(FORMAT(SUM(COUNT_OWN), '##,##0'), 0) AS OWN, IFNULL(FORMAT(SUM(COUNT_FAL), '##,##0'), 0) AS FAL, IFNULL(FORMAT(SUM(COUNT_LEGAL), '##,##0'), 0) AS LEGAL, IFNULL(FORMAT(SUM(COUNT_SYS), '##,##0'), 0) AS SYS, IFNULL(FORMAT(SUM(COUNT_DEL), '##,##0'), 0) AS DEL FROM (SELECT PR.TARGET_ID, PR.AP_NO, COUNT(PR.HASH_ID) AS 'COUNT_OWN', (CASE WHEN PR.PROCESSING_FLAG NOT IN (1,2) THEN COUNT(PR.HASH_ID) ELSE 0 END) AS 'COUNT_FAL', (CASE WHEN PR.PROCESSING_FLAG = 3 THEN COUNT(PR.HASH_ID) ELSE 0 END) AS 'COUNT_LEGAL', (CASE WHEN PR.PROCESSING_FLAG = 5 THEN COUNT(PR.HASH_ID) ELSE 0 END) AS 'COUNT_SYS', (CASE WHEN PR.PROCESSING_FLAG = 1 THEN COUNT(PR.HASH_ID) ELSE 0 END) AS 'COUNT_DEL' FROM pi_ap_server AP, pi_data_processing PR LEFT OUTER JOIN pi_targets T ON PR.TARGET_ID = T.TARGET_ID AND PR.AP_NO = T.AP_NO WHERE T.AP_NO = AP.AP_NO AND AP.IS_SERVER = 1 AND T.TARGET_USE = 'Y'
AND T.TARGET_ID = #{target_id}
GROUP BY PR.TARGET_ID, PR.AP_NO ) D

SELECT D.TARGET_ID, D.AP_NO, FORMAT(SUM(D.PATH_CNT), '##,##0') AS PATH_CNT, FORMAT(SUM(D.COMPLETE), '##,##0') AS COMPLETE, FORMAT(SUM(D.PATH_CNT) - SUM(D.COMPLETE), '##,##0') AS INCOMPLETE FROM (SELECT MAX(TC.REGDATE) AS REGDATE, T.TARGET_ID, T.AP_NO, T.NAME, IFNULL(TC.PATH_CNT, 0) AS PATH_CNT, (SELECT COUNT(*) FROM pi_data_processing DP WHERE TC.TARGET_ID = DP.TARGET_ID AND TC.AP_NO = DP.AP_NO AND DP.APPROVAL_STATUS = 'E') AS COMPLETE FROM pi_targets T LEFT OUTER JOIN pi_total TC ON T.TARGET_ID = TC.TARGET_ID AND T.AP_NO = TC.AP_NO WHERE 1=1
AND T.TARGET_ID = #{target_id}
GROUP BY T.TARGET_ID, T.AP_NO )D LEFT OUTER JOIN pi_total TC ON TC.TARGET_ID = D.TARGET_ID AND TC.AP_NO = D.AP_NO AND TC.REGDATE = D.REGDATE WHERE 1=1 ORDER BY D.PATH_CNT DESC

SELECT D.TARGET_ID, D.AP_NO, FORMAT(SUM(D.PATH_CNT), '##,##0') AS PATH_CNT, FORMAT(SUM(D.COMPLETE), '##,##0') AS COMPLETE, FORMAT(SUM(D.PATH_CNT) - SUM(D.COMPLETE), '##,##0') AS INCOMPLETE FROM (SELECT MAX(TC.REGDATE) AS REGDATE, T.TARGET_ID, T.AP_NO, T.NAME, IFNULL(TC.PATH_CNT, 0) AS PATH_CNT, (SELECT COUNT(*) FROM pi_data_processing DP WHERE TC.TARGET_ID = DP.TARGET_ID AND TC.AP_NO = DP.AP_NO AND DP.APPROVAL_STATUS = 'E') AS COMPLETE FROM pi_targets T LEFT OUTER JOIN pi_total TC ON T.TARGET_ID = TC.TARGET_ID AND T.AP_NO = TC.AP_NO WHERE 1=1
AND T.TARGET_ID IN (
#{item}
)
GROUP BY T.TARGET_ID, T.AP_NO )D LEFT OUTER JOIN pi_total TC ON TC.TARGET_ID = D.TARGET_ID AND TC.AP_NO = D.AP_NO AND TC.REGDATE = D.REGDATE WHERE 1=1 ORDER BY D.PATH_CNT DESC

SELECT IFNULL(FORMAT(SUM(COUNT_OWN), '##,##0'), 0) AS OWN, IFNULL(FORMAT(SUM(COUNT_FAL), '##,##0'), 0) AS FAL, IFNULL(FORMAT(SUM(COUNT_LEGAL), '##,##0'), 0) AS LEGAL, IFNULL(FORMAT(SUM(COUNT_SYS), '##,##0'), 0) AS SYS, IFNULL(FORMAT(SUM(COUNT_DEL), '##,##0'), 0) AS DEL FROM (SELECT PR.TARGET_ID, PR.AP_NO, COUNT(PR.HASH_ID) AS 'COUNT_OWN', (CASE WHEN PR.PROCESSING_FLAG NOT IN (1,2) THEN COUNT(PR.HASH_ID) ELSE 0 END) AS 'COUNT_FAL', (CASE WHEN PR.PROCESSING_FLAG = 3 THEN COUNT(PR.HASH_ID) ELSE 0 END) AS 'COUNT_LEGAL', (CASE WHEN PR.PROCESSING_FLAG = 5 THEN COUNT(PR.HASH_ID) ELSE 0 END) AS 'COUNT_SYS', (CASE WHEN PR.PROCESSING_FLAG = 1 THEN COUNT(PR.HASH_ID) ELSE 0 END) AS 'COUNT_DEL' FROM pi_ap_server AP, pi_data_processing PR LEFT OUTER JOIN pi_targets T ON PR.TARGET_ID = T.TARGET_ID AND PR.AP_NO = T.AP_NO WHERE T.AP_NO = AP.AP_NO
AND PR.TARGET_ID IN (
#{item}
)
GROUP BY PR.TARGET_ID, PR.AP_NO
) D

SELECT D.TARGET_ID, D.AP_NO, D.PLATFORM, D.NAME AS SERVER, D.FILE, D.COUNT FROM (SELECT MAX(TC.REGDATE) AS REGDATE, T.TARGET_ID, T.AP_NO, T.NAME AS FULL_NAME, T.TARGET_USE, IFNULL(TC.PATH_CNT, 0) AS FILE, IFNULL(TC.TOTAL, 0) AS COUNT, SUBSTRING_INDEX(T.NAME, '.', 1) AS HOST_NAME, SUBSTRING_INDEX(SUBSTRING_INDEX(T.NAME, '.', -2), '.', 1) AS NAME, SUBSTRING_INDEX(T.NAME, '.', -1) AS SERIAL, T.PLATFORM FROM pi_ap_server AP, pi_targets T LEFT OUTER JOIN (SELECT PTC.* FROM pi_total PTC, (SELECT MAX(regdate) AS REGDATE, target_id,ap_no FROM pi_total GROUP BY target_id) DTC WHERE PTC.target_id = DTC.TARGET_ID AND PTC.regdate = DTC.REGDATE AND PTC.ap_no = DTC.AP_NO) TC ON T.TARGET_ID = TC.TARGET_ID AND T.AP_NO = TC.AP_NO WHERE 1=1 AND T.AP_NO = AP.AP_NO
AND T.TARGET_ID IN (
#{item}
)
GROUP BY T.TARGET_ID, T.AP_NO )D WHERE 1=1 ORDER BY D.FILE DESC

SELECT D.TARGET_ID, D.AP_NO, D.PLATFORM, D.NAME AS SERVER, D.FILE, D.COUNT FROM (SELECT MAX(TC.REGDATE) AS REGDATE, T.TARGET_ID, T.AP_NO, T.NAME AS FULL_NAME, T.TARGET_USE, IFNULL(TC.PATH_CNT, 0) AS FILE, IFNULL(TC.TOTAL, 0) AS COUNT, SUBSTRING_INDEX(T.NAME, '.', 1) AS HOST_NAME, SUBSTRING_INDEX(SUBSTRING_INDEX(T.NAME, '.', -2), '.', 1) AS NAME, SUBSTRING_INDEX(T.NAME, '.', -1) AS SERIAL, T.PLATFORM FROM pi_ap_server AP, pi_targets T LEFT OUTER JOIN (SELECT PTC.* FROM pi_total PTC, (SELECT MAX(regdate) AS REGDATE, target_id,ap_no FROM pi_total GROUP BY target_id) DTC WHERE PTC.target_id = DTC.TARGET_ID AND PTC.regdate = DTC.REGDATE AND PTC.ap_no = DTC.AP_NO) TC ON T.TARGET_ID = TC.TARGET_ID AND T.AP_NO = TC.AP_NO WHERE 1=1 AND T.AP_NO = AP.AP_NO AND T.TARGET_USE = 'Y'
AND T.TARGET_ID IN (
#{item}
)
AND T.TARGET_ID = ''
GROUP BY T.TARGET_ID, T.AP_NO )D WHERE 1=1 ORDER BY D.FILE DESC

SELECT D.AP_NO, D.TOTAL, D.ERROR, D.SEARCHED, D.WAIT, D.COMPLETE, D.PAUSE, D.SCANCOMP, SUM(D.COMPLETE + D.SCANCOMP) AS PROGRESS_COMPLETE, IFNULL(TRUNCATE(SUM(D.COMPLETE + D.SCANCOMP) / D.TOTAL * 100, 1), 0.0) AS VALUE, CONCAT(IFNULL(TRUNCATE(SUM(D.COMPLETE + D.SCANCOMP) / D.TOTAL * 100, 1), 0.0), '%') AS PERCENT FROM( SELECT A.AP_NO AS AP_NO, A.TARGET_ID, COUNT(A.TARGET_ID) AS TOTAL, COUNT(CASE WHEN A.SEARCH_STATUS = 'ERROR' THEN 1 END) AS ERROR, COUNT(CASE WHEN A.SEARCH_STATUS = 'SEARCHING' THEN 1 END) AS SEARCHED, COUNT(CASE WHEN A.SEARCH_STATUS = 'NONE' AND A.SEARCH_TIME = 0 THEN 1 END) AS WAIT, COUNT( CASE WHEN A.SEARCH_STATUS = 'NONE' AND A.SEARCH_TIME != 0 AND A.MATCHCNT = 0 OR A.SEARCH_STATUS = 'SEARCHED' AND A.MATCHCNT = 0 AND A.SEARCH_TIME != 0 THEN 1 END ) AS COMPLETE, COUNT(CASE WHEN INSTR(UPPER(A.SEARCH_STATUS), 'PAUSED') > 0 THEN 1 END) AS PAUSE, COUNT(CASE WHEN A.SEARCH_STATUS = 'NONE' AND A.MATCHCNT != 0 AND A.SEARCH_TIME != 0 OR A.SEARCH_STATUS = 'SEARCHED' AND A.MATCHCNT != 0 AND A.SEARCH_TIME != 0 THEN 1 END) AS SCANCOMP FROM (SELECT SG.SCHEDULE_GROUP_ID, SG.USER_NO, SG.STATUS, T.TARGET_ID, T.AP_NO, T.SEARCH_STATUS, T.SEARCH_TIME, T.MATCHCNT, SG.TYPE, DATE_FORMAT(T.REGDATE, '%Y%m') AS ID, DATE_FORMAT(T.REGDATE, '%Y년 %m월') AS REGDATE FROM pi_schedule_group SG, pi_targets T WHERE 1=1 AND SG.TYPE = 0
AND T.TARGET_ID IN (
#{item}
)
AND T.TARGET_USE = 'Y' GROUP BY REGDATE, T.TARGET_ID, T.AP_NO ) A ) D UNION ALL SELECT D.AP_NO, D.TOTAL, D.ERROR, D.SEARCHED, D.WAIT, D.COMPLETE, D.PAUSE, D.SCANCOMP, SUM(D.COMPLETE + D.SCANCOMP) AS PROGRESS_COMPLETE, IFNULL(TRUNCATE(SUM(D.COMPLETE + D.SCANCOMP) / D.TOTAL * 100, 1), 0.0) AS VALUE, CONCAT(IFNULL(TRUNCATE(SUM(D.COMPLETE + D.SCANCOMP) / D.TOTAL * 100, 1), 0.0), '%') AS PERCENT FROM( SELECT A.AP_NO AS AP_NO, A.TARGET_ID, COUNT(A.TARGET_ID) AS TOTAL, COUNT(CASE WHEN A.SEARCH_STATUS = 'ERROR' THEN 1 END) AS ERROR, COUNT(CASE WHEN A.SEARCH_STATUS = 'SEARCHING' THEN 1 END) AS SEARCHED, COUNT(CASE WHEN A.SEARCH_STATUS = 'NONE' AND A.SEARCH_TIME = 0 THEN 1 END) AS WAIT, COUNT( CASE WHEN A.SEARCH_STATUS = 'NONE' AND A.SEARCH_TIME != 0 AND A.MATCHCNT = 0 OR A.SEARCH_STATUS = 'SEARCHED' AND A.MATCHCNT = 0 AND A.SEARCH_TIME != 0 THEN 1 END ) AS COMPLETE, COUNT(CASE WHEN INSTR(UPPER(A.SEARCH_STATUS), 'PAUSED') > 0 THEN 1 END) AS PAUSE, COUNT(CASE WHEN A.SEARCH_STATUS = 'NONE' AND A.MATCHCNT != 0 AND A.SEARCH_TIME != 0 OR A.SEARCH_STATUS = 'SEARCHED' AND A.MATCHCNT != 0 AND A.SEARCH_TIME != 0 THEN 1 END) AS SCANCOMP FROM (SELECT SG.SCHEDULE_GROUP_ID, SG.USER_NO, SG.STATUS, T.TARGET_ID, T.AP_NO, T.SEARCH_STATUS, T.SEARCH_TIME, T.MATCHCNT, SG.TYPE, DATE_FORMAT(T.REGDATE, '%Y%m') AS ID, DATE_FORMAT(T.REGDATE, '%Y년 %m월') AS REGDATE FROM pi_schedule_group SG, pi_targets T WHERE 1=1 AND SG.TYPE = 0 AND T.PLATFORM = 'Remote Access Only'
AND TARGET_ID IN (
#{item}
)
AND T.TARGET_USE = 'Y' GROUP BY REGDATE, T.TARGET_ID, T.AP_NO ) A ) D

SELECT ROW_NUMBER() OVER(ORDER BY RATE DESC) AS NUM, F.TARGET_ID, F.AP_NO, F.NAME, F.SERVICE_CODE, F.SERVICE_NM, F.MAX_PATH_CNT, F.MAX_TOTAL, CONCAT(ROUND(F.MAX_TOTAL / F.MIN_TOTAL * 100) , '%') AS RATE, DATE_FORMAT(F.MAX_DATE, '%Y-%m-%d') AS MAX_DATE, F.MIN_PATH_CNT, F.MIN_TOTAL, DATE_FORMAT(F.MIN_DATE, '%Y-%m-%d') AS MIN_DATE, F.COMPLETED, DATE_FORMAT(F.DATE_COMPLETED, '%Y-%m-%d %H:%i:%s') AS DATE_COMPLETED FROM (SELECT D.TARGET_ID, D.AP_NO, D.NAME, D.SERVICE_CODE, D.SERVICE_NM, (SELECT TP.PATH_CNT FROM pi_total TP WHERE TP.REGDATE = D.MAX_DATE AND TP.TARGET_ID = D.TARGET_ID AND TP.AP_NO = D.AP_NO) AS MAX_PATH_CNT, (SELECT TP.TOTAL FROM pi_total TP WHERE TP.REGDATE = D.MAX_DATE AND TP.TARGET_ID = D.TARGET_ID AND TP.AP_NO = D.AP_NO) AS MAX_TOTAL, D.MAX_DATE, (SELECT TP.PATH_CNT FROM pi_total TP WHERE TP.REGDATE = D.MIN_DATE AND TP.TARGET_ID = D.TARGET_ID AND TP.AP_NO = D.AP_NO) AS MIN_PATH_CNT, (SELECT TP.TOTAL FROM pi_total TP WHERE TP.REGDATE = D.MIN_DATE AND TP.TARGET_ID = D.TARGET_ID AND TP.AP_NO = D.AP_NO) AS MIN_TOTAL, D.MIN_DATE, (SELECT COUNT(SCHEDULE_STATUS) FROM pi_schedules S WHERE D.TARGET_ID = S.SCHEDULE_TARGET_ID AND SCHEDULE_STATUS = 'completed') AS COMPLETED, (SELECT MAX(REGDATE) FROM pi_schedules S WHERE D.TARGET_ID = S.SCHEDULE_TARGET_ID AND SCHEDULE_STATUS = 'completed') AS DATE_COMPLETED FROM (SELECT T.TARGET_ID, T.AP_NO, T.NAME, TU.SERVICE_CODE, TU.SERVICE_NM, MAX(TC.REGDATE) AS MAX_DATE, MIN(TC.REGDATE) AS MIN_DATE FROM pi_total TC, pi_targets T LEFT OUTER JOIN pi_target_user TU ON T.TARGET_ID = TU.TARGET_ID AND T.AP_NO = TU.AP_NO WHERE TC.TARGET_ID = T.TARGET_ID AND TC.AP_NO = T.AP_NO
AND T.TARGET_ID IN (
#{item}
)
GROUP BY TARGET_ID, AP_NO) D ) F
